  "Orientação e gestão das contribuições para a Segurança Social em Portugal: regime de trabalhador independente, isenções disponíveis e impacto nos direitos futuros.": { en: "Guidance and management of Social Security contributions in Portugal: self-employed regime, available exemptions, and impact on future rights.", es: "Orientación y gestión de las cotizaciones a la Seguridad Social en Portugal: régimen de trabajador independiente, exenciones disponibles e impacto en los derechos futuros." },
  "Orientação inicial para quem pretende empreender em Portugal: estrutura, enquadramento, primeiros passos e ligação a parceiros especializados.": { en: "Initial guidance for those looking to start a business in Portugal: structure, framework, first steps, and connection to specialized partners.", es: "Orientación inicial para quienes desean emprender en Portugal: estructura, encuadre, primeros pasos y conexión con socios especializados." },
  "Orientação sobre as principais opções de investimento em Portugal: imobiliário, fundos, depósitos, negócios e condições fiscais associadas a cada classe de ativo.": { en: "Guidance on the main investment options in Portugal: real estate, funds, deposits, businesses, and tax conditions associated with each asset class.", es: "Orientación sobre las principales opciones de inversión en Portugal: inmobiliaria, fondos, depósitos, negocios y condiciones fiscales asociadas a cada clase de activo." },
  "Orientação sobre costumes, códigos sociais, gastronomia, tradições e formas de relacionamento típicas da cultura portuguesa, para uma integração real e não superficial.": { en: "Guidance on customs, social codes, gastronomy, traditions, and typical relationship styles of Portuguese culture, for real and non-superficial integration.", es: "Orientación sobre costumbres, códigos sociales, gastronomía, tradiciones y formas de relación típicas de la cultura portuguesa, para una integración real y no superficial." },
  "Orientação sobre ginásios, desporto, atividades para crianças, espaços ao ar livre e rotinas de bem-estar adaptadas ao novo contexto de vida em Portugal.": { en: "Guidance on gyms, sports, children's activities, outdoor spaces, and well-being routines adapted to the new living context in Portugal.", es: "Orientación sobre gimnasios, deportes, actividades para niños, espacios al aire libre y rutinas de bienestar adaptadas al nuevo contexto de vida en Portugal." },
  "Orientação sobre reconhecimento de diplomas, equivalências e certificações necessárias para o exercício da profissão em Portugal e na União Europeia.": { en: "Guidance on diploma recognition, equivalences, and certifications required for exercising a profession in Portugal and the European Union.", es: "Orientación sobre reconocimiento de títulos, equivalencias y certificaciones necesarias para el ejercicio de la profesión en Portugal y la Unión Europea." },
  "PB4 (Cobertura de Saúde Internacional)": { en: "PB4 (International Health Coverage)", es: "PB4 (Cobertura de Salud Internacional)" },
  "Pablo Alejandro Saco Paim é Co-Founder e Estrategista de Ativos Digitais da MOOVIA Portugal, atuando na interseção entre investimentos, tecnologia e novas dinâmicas globais de alocação patrimonial e mobilidade internacional.": { en: "Pablo Alejandro Saco Paim is Co-Founder & CPTO of MOOVIA Portugal.", es: "Pablo Alejandro Saco Paim es cofundador y CPTO de MOOVIA Portugal." },
  "Para chegadas urgentes ou períodos de transição: identificação de acomodações temporárias de qualidade com negociação de valor e condições de permanência estendida.": { en: "For urgent arrivals or transition periods: sourcing quality temporary accommodation, including negotiating rates and conditions for an extended stay.", es: "Para llegadas urgentes o periodos de transición: identificación de alojamientos temporales de calidad con negociación de valor y condiciones de estancia extendida." },
