  "Processo de alteração da residência fiscal do Brasil para Portugal, com análise do impacto no Brasil (saída definitiva ou temporária) e entrada no sistema português.": { en: "Process for changing tax residency from Brazil to Portugal, including an analysis of the impact in Brazil (permanent or temporary departure) and entry into the Portuguese tax system.", es: "Proceso de cambio de residencia fiscal de Brasil a Portugal, con análisis del impacto en Brasil (salida definitiva o temporal) y entrada en el sistema portugués." },
  "Processo de regularização de situações fiscais em dívida ou irregulares junto à Autoridade Tributária, com plano de pagamento e resolução estruturada.": { en: "Process for regularising outstanding or irregular tax situations with the Tax Authority, including a payment plan and structured resolution.", es: "Proceso de regularización de situaciones fiscales pendientes o irregulares ante la Autoridad Tributaria, con plan de pago y resolución estructurada." },
  "Processo de troca ou validação da carta de condução estrangeira em Portugal, incluindo prazos e documentação necessária.": { en: "Process for exchanging or validating a Brazilian driving licence in Portugal, including required documentation and timeframes.", es: "Proceso de canje o validación del carnet de conducir brasileño en Portugal, incluyendo plazos y documentación necesaria." },
  "Processo de validação e equivalência de títulos académicos obtidos no Brasil junto às entidades competentes em Portugal.": { en: "Process for the validation and recognition of academic degrees obtained in Brazil by the relevant authorities in Portugal.", es: "Proceso de validación y equivalencia de títulos académicos obtenidos en Brasil ante las entidades competentes en Portugal." },
  "Processo para obtenção do Estatuto de Igualdade de Direitos e Deveres para cidadãos brasileiros em Portugal, amplia direitos de residência e acesso a serviços públicos.": { en: "Process for obtaining the Statute of Equal Rights and Duties for Brazilian citizens in Portugal, which expands residency rights and access to public services.", es: "Proceso para la obtención del Estatuto de Igualdad de Derechos y Deberes para ciudadanos brasileños en Portugal, amplía los derechos de residencia y el acceso a los servicios públicos." },
